#!/usr/bin/env python3 """Verify native tool passthrough and narrative fast-path on sovereign proxy.""" from __future__ import annotations import json import time import urllib.request PROXY = "http://127.0.0.1:8091/v1/chat/completions" EXPECTED_BACKEND = "qwen2-5-7b" def post(body: dict, *, timeout: int = 180) -> dict: req = urllib.request.Request( PROXY, data=json.dumps(body).encode(), headers={"Content-Type": "application/json"}, ) with urllib.request.urlopen(req, timeout=timeout) as resp: return json.loads(resp.read()) def test_tool_passthrough() -> tuple[bool, str]: tools = [ { "type": "function", "function": { "name": "bash", "description": "Execute a bash command", "parameters": { "type": "object", "properties": {"command": {"type": "string"}}, "required": ["command"], }, }, } ] body = { "model": "phronesis-sovereign-auto", "messages": [ { "role": "user", "content": "Use the bash tool to run: echo HERMES_TOOL_OK", } ], "tools": tools, "tool_choice": "auto", "max_tokens": 256, } started = time.time() try: r = post(body) except Exception as exc: return False, f"request failed: {exc}" elapsed = round(time.time() - started, 2) msg = (r.get("choices") or [{}])[0].get("message") or {} tool_calls = msg.get("tool_calls") or [] model = str(r.get("model") or "") prov = r.get("phronesis_provenance") or {} backend = str(prov.get("resolved_model") or model) if tool_calls: fn = (tool_calls[0].get("function") or {}) return True, ( f"tool_call received name={fn.get('name')} " f"args={str(fn.get('arguments'))[:120]} backend={backend} {elapsed}s" ) content = str(msg.get("content") or "") if "[insert output" in content.lower() or "placeholder" in content.lower(): return False, f"hallucinated placeholder content backend={backend} {elapsed}s" return False, f"no tool_calls in response model={model} content={content[:200]} {elapsed}s" def test_narrative_fast_path() -> tuple[bool, str]: body = { "model": "phronesis-sovereign-auto", "messages": [ { "role": "user", "content": ( "ROLEPLAY_MODE: The party enters a blood-soaked throne room. " "Describe in vivid prose. No disclaimers." ), } ], "max_tokens": 256, "extra_body": { "phronesis": { "platform": "alice-roleplay", "narrative_fast": True, "suppress_reasoning": True, } }, } started = time.time() try: r = post(body, timeout=180) except Exception as exc: return False, f"request failed: {exc}" elapsed = round(time.time() - started, 2) msg = (r.get("choices") or [{}])[0].get("message") or {} content = str(msg.get("content") or "") prov = r.get("phronesis_provenance") or {} if not ( prov.get("suppress_reasoning") or prov.get("narrative_fast") or prov.get("routing_platform") == "alice-roleplay" ): return False, f"reasoning not suppressed in provenance prov={prov}" if msg.get("reasoning") or msg.get("reasoning_content"): return False, "reasoning fields present in message payload" if "<think>" in content.lower() or "reasoning:" in content.lower(): return False, f"think/reasoning block leaked into content ({elapsed}s)" if len(content.strip()) < 80: return False, f"response too short ({elapsed}s): {content!r}" if elapsed > 90: return False, f"latency too high: {elapsed}s" return True, f"prose ok chars={len(content)} latency={elapsed}s backend={prov.get('resolved_model')}" def main() -> int: print("=== Tool + Narrative Verification ===") failures = [] ok_a, msg_a = test_tool_passthrough() print(f"Test A (tool passthrough): {'PASS' if ok_a else 'FAIL'} {msg_a}") if not ok_a: failures.append("tool_passthrough") ok_b, msg_b = test_narrative_fast_path() print(f"Test B (narrative fast): {'PASS' if ok_b else 'FAIL'} {msg_b}") if not ok_b: failures.append("narrative_fast") if failures: print("FAILURES:", failures) return 1 print("ALL CHECKS PASSED") return 0 if __name__ == "__main__": raise SystemExit(main())